def scene_one(score):
    print("\n=== Scene One ===")
    print("You are at the start of your adventure.")
    print("1) Choice A")
    print("2) Choice B")
    choice = input("Choose (1/2): ")
    if choice == "1":
        print("Something good happens!")
        return "end", score + 10
    else:
        print("Something tricky happens.")
        return "end", score + 5

def scene_end(score):
    print("\n=== The End ===")
    # Print a message based on score
    if score >= 10:
        print("Great adventurer! Score:", score)
    else:
        print("You survived. Score:", score)

# Game loop
score = 0
current = "one"
playing = True

while playing:
    if current == "one":
        current, score = scene_one(score)
    elif current == "end":
        scene_end(score)
        playing = False
